mapper.select:
/*RateGiftPrmtMapper.selectRateGiftPrmtCount*/
SELECT COUNT(A.SEQ)
FROM NMCP_RATE_GIFT_PRMT A
    ,MSP_GIFT_PRMT@DL_MSP B
WHERE A.PRMT_ID = B.PRMT_ID
  AND A.DEL_YN = 'N'

  AND B.PRMT_TYPE = #{srchPrmtType}


  AND A.PRMT_ID = #{srchName}


  AND UPPER(B.PRMT_NM) LIKE '%' || UPPER(#{srchName}) || '%'

/*RateGiftPrmtMapper.selectRateGiftPrmtList*/ SELECT A.SEQ ,A.PRMT_ID ,B.PRMT_NM ,B.PRMT_TYPE ,FN_GET_CODENM@DL_MSP('ORG1010', B.PRMT_TYPE) AS PRMT_TYPE_NM ,A.INDC_ODRG ,A.STAT_VAL ,A.PSTNG_START_DATE ,A.PSTNG_END_DATE ,A.PSTNG_START_DATE_SEC ,A.PSTNG_END_DATE_SEC FROM NMCP_RATE_GIFT_PRMT A ,MSP_GIFT_PRMT@DL_MSP B WHERE A.PRMT_ID = B.PRMT_ID AND A.DEL_YN = 'N'
AND B.PRMT_TYPE = #{srchPrmtType}
AND A.PRMT_ID = #{srchName}
AND UPPER(B.PRMT_NM) LIKE '%' || UPPER(#{srchName}) || '%'
ORDER BY A.STAT_VAL DESC, DECODE(A.INDC_ODRG, 0, 99999, A.INDC_ODRG), A.CRET_DTTM DESC

/*RateGiftPrmtMapper.selectGiftPrmtCount*/
SELECT COUNT(PRMT_ID)
FROM MSP_GIFT_PRMT@DL_MSP
WHERE STRT_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}

  AND ORGN_ID = #{srchOrgnId}


  AND PRMT_TYPE = #{srchPrmtType}


  AND PRMT_ID = #{srchName}


  AND UPPER(PRMT_NM) LIKE '%' || UPPER(#{srchName}) || '%'


  AND USG_YN = #{srchUseYn}


  AND SHOW_YN = #{srchShowYn}

/*RateGiftPrmtMapper.selectGiftPrmtList*/ SELECT PRMT_ID ,PRMT_NM ,STRT_DT ,TO_CHAR(TO_DATE(STRT_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS STRT_DT_FMT ,END_DT ,TO_CHAR(TO_DATE(END_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS END_DT_FMT ,ORGN_ID ,FN_GET_CODENM@DL_MSP('CMN0268', ORGN_ID) AS ORGN_ID_NM ,ORGN_TYPE ,FN_GET_CODENM@DL_MSP('CMN0055', ORGN_TYPE) AS ORGN_TYPE_NM ,PRMT_TYPE ,FN_GET_CODENM@DL_MSP('ORG1010', PRMT_TYPE) AS PRMT_TYPE_NM ,PRMT_TEXT ,USG_YN ,SHOW_YN ,WIRELESS_YN FROM MSP_GIFT_PRMT@DL_MSP WHERE STRT_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND ORGN_ID = #{srchOrgnId}
AND PRMT_TYPE = #{srchPrmtType}
AND PRMT_ID = #{srchName}
AND UPPER(PRMT_NM) LIKE '%' || UPPER(#{srchName}) || '%'
AND USG_YN = #{srchUseYn}
AND SHOW_YN = #{srchShowYn}
ORDER BY STRT_DT DESC, REGST_DTTM DESC
